@inherits LayoutComponentBase
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="wizard-progress px-4 py-3">
            <h5 class="mb-2">Job Application — Step @currentStep of @totalSteps</h5>
            <div class="d-flex gap-2 mb-2">
                @for (int i = 0; i < totalSteps; i++)
                {
                    var step = steps[i];
                    var stepNum = i + 1;
                    var cssClass = stepNum == currentStep ? "active"
                                 : stepNum < currentStep ? "completed"
                                 : "pending";
                    <a href="@step.Href" class="step-link @cssClass">
                        <span class="step-number">@stepNum</span>
                        <span class="step-label">@step.Label</span>
                    </a>
                }
            </div>
            <div class="progress" style="height: 6px;">
                <div class="progress-bar" role="progressbar"
                     style="width: @(currentStep * 100 / totalSteps)%"></div>
            </div>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private record StepInfo(string Label, string Href);

    private static readonly StepInfo[] steps =
    [
        new("Personal Info", "/apply/personal-info"),
        new("Experience", "/apply/experience"),
        new("References", "/apply/references"),
        new("Review", "/apply/review")
    ];

    private const int totalSteps = 4;
    private int currentStep = 1;

    protected override void OnParametersSet()
    {
        var path = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
        currentStep = Array.FindIndex(steps, s =>
            path.Equals(s.Href, StringComparison.OrdinalIgnoreCase)) + 1;

        if (currentStep < 1) currentStep = 1;
    }
}

.wizard-progress {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
}

.step-link {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.35rem 0.75rem;
    border-radius: 1rem;
    text-decoration: none;
    font-size: 0.85rem;
    border: 1px solid #dee2e6;
    color: #6c757d;
    background: #fff;
}

    .step-link.active {
        background: #0d6efd;
        color: #fff;
        border-color: #0d6efd;
        font-weight: 600;
    }

    .step-link.completed {
        background: #198754;
        color: #fff;
        border-color: #198754;
    }

    .step-link:hover {
        text-decoration: none;
        opacity: 0.9;
    }

.step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.4rem;
    height: 1.4rem;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.3);
    font-size: 0.75rem;
    font-weight: 700;
}

.step-label {
    display: none;
}

@media (min-width: 641px) {
    .step-label {
        display: inline;
    }
}

