@page "/apply/review"
@rendermode InteractiveServer
@layout ApplicationWizardLayout
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Review — Application</PageTitle>

<h3>Review Your Application</h3>

<div style="max-width: 600px;">
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="/apply/personal-info" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            <p><strong>Name:</strong> @AppState.PersonalInfo.Name</p>
            <p class="mb-0"><strong>Email:</strong> @AppState.PersonalInfo.Email</p>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work Experience</strong>
            <a href="/apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @foreach (var job in AppState.JobHistory)
            {
                <div class="mb-2">
                    <strong>@job.Title</strong> at @job.Company
                    @if (!string.IsNullOrEmpty(job.Years))
                    {
                        <span class="text-muted">(@job.Years)</span>
                    }
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="/apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
        </div>
        <div class="card-body">
            @foreach (var r in AppState.References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship
                    @if (!string.IsNullOrEmpty(r.Phone))
                    {
                        <span class="text-muted">(@r.Phone)</span>
                    }
                </div>
            }
        </div>
    </div>
</div>

<div class="d-flex gap-2 mt-3">
    <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (submitted)
{
    <div class="alert alert-success mt-3" style="max-width: 600px;">
        Your application has been submitted successfully!
    </div>
}

@code {
    private bool submitted;

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        submitted = true;
    }
}

