@page "/apply/personal-info"
@rendermode InteractiveServer
@layout ApplicationWizardLayout
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Personal Info — Application</PageTitle>

<h3>Personal Information</h3>

<div class="mb-3" style="max-width: 500px;">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="AppState.PersonalInfo.Name" />
</div>

<div class="mb-3" style="max-width: 500px;">
    <label class="form-label">Email</label>
    <input class="form-control" type="email" @bind="AppState.PersonalInfo.Email" />
</div>

<div class="d-flex gap-2 mt-4">
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void Next()
    {
        AppState.NotifyStateChanged();
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout ApplicationWizardLayout
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Experience — Application</PageTitle>

<h3>Work Experience</h3>

@for (int i = 0; i < AppState.JobHistory.Count; i++)
{
    var index = i;
    var entry = AppState.JobHistory[index];
    <div class="card mb-3" style="max-width: 600px;">
        <div class="card-body">
            <div class="d-flex justify-content-between">
                <strong>Position @(index + 1)</strong>
                @if (AppState.JobHistory.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger"
                            @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>
            <div class="mb-2 mt-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="entry.Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="entry.Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Years</label>
                <input class="form-control" @bind="entry.Years" placeholder="e.g. 2020–2023" />
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add another position</button>

<div class="d-flex gap-2 mt-2">
    <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddEntry() => AppState.JobHistory.Add(new());

    private void RemoveEntry(int index) => AppState.JobHistory.RemoveAt(index);

    private void Back()
    {
        AppState.NotifyStateChanged();
        Nav.NavigateTo("/apply/personal-info");
    }

    private void Next()
    {
        AppState.NotifyStateChanged();
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@layout ApplicationWizardLayout
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>References — Application</PageTitle>

<h3>References</h3>

@for (int i = 0; i < AppState.References.Count; i++)
{
    var index = i;
    var refContact = AppState.References[index];
    <div class="card mb-3" style="max-width: 600px;">
        <div class="card-body">
            <div class="d-flex justify-content-between">
                <strong>Reference @(index + 1)</strong>
                @if (AppState.References.Count > 1)
                {
                    <button class="btn btn-sm btn-outline-danger"
                            @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>
            <div class="mb-2 mt-2">
                <label class="form-label">Name</label>
                <input class="form-control" @bind="refContact.Name" />
            </div>
            <div class="mb-2">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="refContact.Relationship"
                       placeholder="e.g. Former Manager" />
            </div>
            <div class="mb-2">
                <label class="form-label">Phone</label>
                <input class="form-control" type="tel" @bind="refContact.Phone" />
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add another reference</button>

<div class="d-flex gap-2 mt-2">
    <button class="btn btn-outline-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddReference() => AppState.References.Add(new());

    private void RemoveReference(int index) => AppState.References.RemoveAt(index);

    private void Back()
    {
        AppState.NotifyStateChanged();
        Nav.NavigateTo("/apply/experience");
    }

    private void Next()
    {
        AppState.NotifyStateChanged();
        Nav.NavigateTo("/apply/review");
    }
}

